function FlipServiceCard({icon,title,desc}){
  const[f,setF]=useState(false);
  return <div onMouseEnter={()=>setF(true)} onMouseLeave={()=>setF(false)} style={{perspective:"800px",height:200,cursor:"default"}}>
    <div style={{position:"relative",width:"100%",height:"100%",transformStyle:"preserve-3d",transition:"transform .55s",transform:f?"rotateY(180deg)":"rotateY(0)"}}>
      <div style={{position:"absolute",inset:0,backfaceVisibility:"hidden",WebkitBackfaceVisibility:"hidden",background:C.zinc,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:14,padding:"24px 18px",border:`1px solid ${C.border}`}}>
        <div style={{fontSize:32}}>{icon}</div>
        <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:16,fontWeight:700,textTransform:"uppercase",color:C.white,textAlign:"center"}}>{title}</div>
      </div>
      <div style={{position:"absolute",inset:0,backfaceVisibility:"hidden",WebkitBackfaceVisibility:"hidden",transform:"rotateY(180deg)",background:`linear-gradient(135deg,#1a0303,${C.red})`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"22px 18px",border:`1px solid ${C.red}`}}>
        <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:15,fontWeight:700,textTransform:"uppercase",color:"#fff",textAlign:"center",marginBottom:10}}>{title}</div>
        <div style={{fontSize:12,color:"rgba(255,255,255,.85)",lineHeight:1.6,fontFamily:"sans-serif",textAlign:"center"}}>{desc}</div>
      </div>
    </div>
  </div>;
}

