function Chatbot(){
  const[open,setOpen]=useState(false);const[msgs,setMsgs]=useState([{from:"bot",text:"¡Hola! Soy el asistente de NordenCars 🚗 ¿En qué puedo ayudarte?"}]);
  const[input,setInput]=useState("");const[typing,setTyping]=useState(false);const endRef=useRef();
  const SYSTEM=`Sos el asistente virtual de NordenCars, agencia de autos en Yerba Buena, Tucumán. Fundadores: Ale y Gonchi. Ale: +54 9 381 477-3142. Gonchi: +54 9 381 518-4961. Dirección: San Lorenzo y Cariola, Galería Mercato, Casco Viejo, Yerba Buena. Horario: Lun-Sáb 9 a 20hs. Instagram: @norden.cars. Respondé en español, amigable y conciso.`;
  useEffect(()=>{endRef.current?.scrollIntoView({behavior:"smooth"});},[msgs,typing]);
  const send=async(text)=>{
    const t=(text||"").trim();if(!t)return;setInput("");setMsgs(m=>[...m,{from:"user",text:t}]);setTyping(true);
    try{
      const history=msgs.slice(-6).map(m=>({role:m.from==="user"?"user":"assistant",content:m.text}));
      const res=await fetch("https://api.anthropic.com/v1/messages",{
        method:"POST",
        headers:{
          "Content-Type":"application/json",
          "x-api-key":"sk-ant-api03-placeholder",
          "anthropic-version":"2023-06-01",
          "anthropic-dangerous-direct-browser-access":"true"
        },
        body:JSON.stringify({model:"claude-haiku-4-5-20251001",max_tokens:400,system:SYSTEM,messages:[...history,{role:"user",content:t}]})
      });
      const data=await res.json();
      if(data.error){
        // Si la API falla, responder con info hardcodeada
        const resp=getLocalResponse(t);
        setMsgs(m=>[...m,{from:"bot",text:resp}]);
      } else {
        setMsgs(m=>[...m,{from:"bot",text:data.content?.[0]?.text||"Disculpá, hubo un error."}]);
      }
    }catch{
      const resp=getLocalResponse(t);
      setMsgs(m=>[...m,{from:"bot",text:resp}]);
    }
    setTyping(false);
  };

  function getLocalResponse(text){
    const t=text.toLowerCase();
    if(t.includes("stock")||t.includes("auto")||t.includes("vehiculo")||t.includes("vehículo")||t.includes("ver"))
      return "¡Podés ver todos nuestros vehículos disponibles en la sección Stock! Tenemos 0km y usados. ¿Necesitás algo en particular?";
    if(t.includes("financ"))
      return "Sí, trabajamos con opciones de financiación personalizada para usados y 0km. Consultanos sin compromiso por WhatsApp: +54 9 381 477-3142 (Ale) o +54 9 381 518-4961 (Gonchi).";
    if(t.includes("permuta")||t.includes("cambio")||t.includes("vender"))
      return "¡Sí! Podemos tomar tu auto como parte de pago. Mandanos fotos y datos de tu vehículo por WhatsApp y te damos una tasación rápida.";
    if(t.includes("ubicacion")||t.includes("ubicación")||t.includes("donde")||t.includes("dónde")||t.includes("direccion"))
      return "Estamos en San Lorenzo y Cariola, Galería Mercato, Casco Viejo, Yerba Buena, Tucumán. Lunes a sábado de 9 a 20hs.";
    if(t.includes("whatsapp")||t.includes("contacto")||t.includes("llamar")||t.includes("teléfono")||t.includes("telefono"))
      return "Podés escribirnos por WhatsApp:\n• Ale: +54 9 381 477-3142\n• Gonchi: +54 9 381 518-4961\nRespondemos a la brevedad!";
    return "¡Hola! Soy el asistente de NordenCars. Podés preguntarme sobre nuestro stock, financiación, permutas o ubicación. También podés contactarnos directamente por WhatsApp con Ale (+54 9 381 477-3142) o Gonchi (+54 9 381 518-4961) 🚗";
  }
  return <>
    <button onClick={()=>setOpen(o=>!o)} style={{position:"fixed",bottom:96,right:28,zIndex:600,width:52,height:52,borderRadius:"50%",border:"none",background:"#1c1c1c",cursor:"pointer",boxShadow:`0 4px 24px rgba(0,0,0,.6),0 0 0 1px ${C.border2}`,display:"flex",alignItems:"center",justifyContent:"center",transition:"all .3s",transform:open?"scale(1.08) rotate(45deg)":"scale(1)"}}>
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={open?C.red:"white"} strokeWidth="2" strokeLinecap="round">{open?<><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></>:<path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>}</svg>
      {!open&&<span style={{position:"absolute",top:-3,right:-3,width:14,height:14,borderRadius:"50%",background:"#22c55e",border:"2px solid #0a0a0a",fontSize:7,color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700,fontFamily:"sans-serif"}}>IA</span>}
    </button>
    {open&&<div style={{position:"fixed",bottom:160,right:28,zIndex:601,width:320,background:"#111",border:`1px solid ${C.border2}`,display:"flex",flexDirection:"column",overflow:"hidden",boxShadow:"0 24px 80px rgba(0,0,0,.85)"}}>
      <div style={{background:`linear-gradient(135deg,#1a0505,${C.red})`,padding:"14px 16px",display:"flex",alignItems:"center",gap:10}}>
        <img src={IMG_LOGO_NAV} alt="NordenCars" style={{height:28,filter:"brightness(10)"}}/>
        <div><div style={{fontSize:12,fontWeight:600,color:"#fff",fontFamily:"sans-serif"}}>Asistente NordenCars</div><div style={{fontSize:9,color:"rgba(255,255,255,.75)",display:"flex",alignItems:"center",gap:4,fontFamily:"sans-serif"}}><span style={{width:5,height:5,background:"#4ade80",borderRadius:"50%",display:"inline-block"}}/>IA activa</div></div>
      </div>
      <div style={{padding:"8px 10px",borderBottom:`1px solid ${C.border}`,display:"flex",flexWrap:"wrap",gap:5}}>
        {["Ver stock","Financiación","Permutas","Ubicación","WhatsApp"].map(t=><button key={t} onClick={()=>send(t)} style={{fontSize:9,padding:"4px 10px",background:"rgba(220,38,38,.08)",border:`1px solid rgba(220,38,38,.18)`,color:C.red,cursor:"pointer",fontFamily:"sans-serif",borderRadius:20}}>{t}</button>)}
      </div>
      <div style={{flex:1,overflowY:"auto",padding:12,display:"flex",flexDirection:"column",gap:8,maxHeight:260,minHeight:180}}>
        {msgs.map((m,i)=><div key={i} style={{display:"flex",justifyContent:m.from==="user"?"flex-end":"flex-start"}}><div style={{maxWidth:"85%",padding:"9px 13px",fontSize:12,lineHeight:1.55,fontFamily:"sans-serif",background:m.from==="user"?C.red:"rgba(255,255,255,.06)",color:"#fff",borderRadius:m.from==="user"?"12px 12px 2px 12px":"12px 12px 12px 2px"}}>{m.text}</div></div>)}
        {typing&&<div style={{display:"flex"}}><div style={{padding:"9px 13px",background:"rgba(255,255,255,.06)",borderRadius:"12px 12px 12px 2px",display:"flex",gap:4,alignItems:"center"}}>{[0,1,2].map(i=><span key={i} style={{width:5,height:5,background:C.muted,borderRadius:"50%",animation:`dot .9s ${i*.2}s infinite`}}/>)}</div></div>}
        <div ref={endRef}/>
      </div>
      <div style={{padding:"9px 11px",borderTop:`1px solid ${C.border}`,display:"flex",gap:7}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send(input)} placeholder="Escribí tu consulta..." style={{flex:1,background:"rgba(255,255,255,.04)",border:`1px solid ${C.border2}`,color:"#fff",padding:"9px 12px",fontSize:11,fontFamily:"sans-serif",outline:"none"}}/>
        <button onClick={()=>send(input)} style={{background:C.red,border:"none",color:"#fff",padding:"0 14px",cursor:"pointer",fontSize:15}}>→</button>
      </div>
    </div>}
    <style>{`@keyframes dot{0%,80%,100%{opacity:.2;transform:scale(.8)}40%{opacity:1;transform:scale(1)}}`}</style>
  </>;
}

