// NAV con menú mobile
function Nav({page,navTo,scrolled}){
  const[menuOpen,setMenuOpen]=useState(false);
  const links=[["home","Inicio"],["stock","Stock"],["nosotros","Nosotros"],["contacto","Contacto"]];
  return <>
    <nav style={{position:"fixed",top:0,left:0,right:0,zIndex:300,background:scrolled||menuOpen?"rgba(8,8,8,.98)":"rgba(8,8,8,.45)",backdropFilter:"blur(22px)",borderBottom:scrolled?`1px solid ${C.border}`:"1px solid transparent",transition:"all .4s"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 5vw",height:68}}>
        {/* Logo texto */}
        <button onClick={()=>{navTo("home");setMenuOpen(false);}} style={{background:"none",border:"none",cursor:"pointer",padding:0,display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
          <span style={{display:"inline-flex",width:8,height:8,background:C.red,transform:"rotate(45deg)",flexShrink:0}}/>
          <span style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:20,fontWeight:900,textTransform:"uppercase",letterSpacing:3,color:C.white,whiteSpace:"nowrap"}}>NORDEN <span style={{color:C.red}}>CARS</span></span>
        </button>

        {/* Desktop links */}
        <div style={{display:"flex",gap:22,alignItems:"center",flexShrink:0,"@media(max-width:768px)":{display:"none"}}}>
          <style>{`@media(max-width:700px){.nav-desktop{display:none!important}}.nav-desktop{display:flex;gap:22px;align-items:center}.nav-hamburger{display:none}@media(max-width:700px){.nav-hamburger{display:flex}}`}</style>
          <div className="nav-desktop">
            {links.map(([p,l])=>(
              <button key={p} onClick={()=>navTo(p)} style={{background:"none",border:"none",cursor:"pointer",fontSize:10,letterSpacing:3,textTransform:"uppercase",fontFamily:"sans-serif",color:page===p?C.white:"rgba(245,245,245,.38)",transition:"color .3s",borderBottom:page===p?`1px solid ${C.red}`:"1px solid transparent",paddingBottom:2,whiteSpace:"nowrap"}}>{l}</button>
            ))}
            <button onClick={()=>navTo("contacto")} style={{background:C.red,border:"none",color:"#fff",padding:"9px 20px",fontSize:9,letterSpacing:2,textTransform:"uppercase",fontFamily:"sans-serif",fontWeight:600,cursor:"pointer",transition:"all .25s",whiteSpace:"nowrap"}} onMouseEnter={e=>{e.target.style.boxShadow=`0 6px 24px ${C.redGlow}`}} onMouseLeave={e=>{e.target.style.boxShadow="none"}}>Consultar</button>
            <button onClick={()=>navTo("admin")} title="Panel admin" style={{background:"none",border:`1px solid ${C.border2}`,color:C.muted,padding:"7px 9px",cursor:"pointer",fontSize:11,lineHeight:1}} onMouseEnter={e=>{e.target.style.borderColor=C.red}} onMouseLeave={e=>{e.target.style.borderColor=C.border2}}>⚙</button>
          </div>
          {/* Hamburger mobile */}
          <button className="nav-hamburger" onClick={()=>setMenuOpen(o=>!o)} style={{background:"none",border:"none",cursor:"pointer",display:"none",flexDirection:"column",gap:5,padding:6,zIndex:2}}>
            <span style={{display:"block",width:24,height:2,background:menuOpen?C.red:C.white,transition:"all .3s",transform:menuOpen?"rotate(45deg) translateY(7px)":"none"}}/>
            <span style={{display:"block",width:24,height:2,background:C.white,transition:"all .3s",opacity:menuOpen?0:1}}/>
            <span style={{display:"block",width:24,height:2,background:menuOpen?C.red:C.white,transition:"all .3s",transform:menuOpen?"rotate(-45deg) translateY(-7px)":"none"}}/>
          </button>
        </div>
      </div>

      {/* Mobile menu desplegable */}
      <div style={{
        maxHeight:menuOpen?"400px":"0",overflow:"hidden",transition:"max-height .4s ease",
        background:"rgba(8,8,8,.98)",borderTop:menuOpen?`1px solid ${C.border}`:"none",
      }}>
        <div style={{padding:"16px 5vw 24px",display:"flex",flexDirection:"column",gap:4}}>
          {links.map(([p,l])=>(
            <button key={p} onClick={()=>{navTo(p);setMenuOpen(false);}} style={{background:"none",border:"none",cursor:"pointer",fontSize:18,letterSpacing:3,textTransform:"uppercase",fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700,color:page===p?C.red:C.white,textAlign:"left",padding:"12px 0",borderBottom:`1px solid ${C.border}`,transition:"color .2s"}}>{l}</button>
          ))}
          <button onClick={()=>{navTo("contacto");setMenuOpen(false);}} style={{marginTop:12,background:C.red,border:"none",color:"#fff",padding:"14px",fontSize:11,letterSpacing:3,textTransform:"uppercase",fontFamily:"sans-serif",fontWeight:600,cursor:"pointer",width:"100%"}}>Consultar ahora</button>
          <button onClick={()=>{navTo("admin");setMenuOpen(false);}} style={{marginTop:8,background:"none",border:`1px solid ${C.border2}`,color:C.muted,padding:"10px",cursor:"pointer",fontSize:9,fontFamily:"sans-serif",letterSpacing:2,textTransform:"uppercase"}}>⚙ Panel Admin</button>
        </div>
      </div>
    </nav>
  </>;
}

function Marquee(){
  const items=["Compra Garantizada","0km y Usados","Financiación","Permutas","Yerba Buena · Tucumán","Transparencia Total","Transferencia Ágil","Sin Letras Chicas","Entregas al NOA"];
  return <div style={{overflow:"hidden",background:C.red,padding:"10px 0"}}>
    <div style={{display:"flex",width:"max-content",animation:"marquee 34s linear infinite"}}>
      {[...Array(2)].flatMap(()=>items.map((t,i)=>(
        <div key={t+i} style={{display:"flex",alignItems:"center",gap:18,padding:"0 32px",whiteSpace:"nowrap",fontSize:9,fontWeight:700,letterSpacing:3.5,textTransform:"uppercase",color:"rgba(255,255,255,.9)",fontFamily:"sans-serif"}}>
          {t}<span style={{width:3,height:3,background:"rgba(255,255,255,.5)",borderRadius:"50%",flexShrink:0}}/>
        </div>
      )))}
    </div>
  </div>;
}

function CarCard({car,onClick}){
  const[hov,setHov]=useState(false);const[imgIdx,setImgIdx]=useState(0);
  const fotos=car.fotos&&car.fotos.length>0?car.fotos:[];
  const km=car.kilometraje!=null?Number(car.kilometraje).toLocaleString("es-AR"):null;
  const price=car.precio_usd?`USD ${Number(car.precio_usd).toLocaleString("es-AR")}`:null;
  return <div onMouseEnter={()=>setHov(true)} onMouseLeave={()=>{setHov(false);setImgIdx(0);}} style={{background:C.zinc,cursor:"pointer",transition:"all .3s",transform:hov?"translateY(-4px)":"translateY(0)",boxShadow:hov?`0 16px 48px rgba(0,0,0,.5),0 0 0 1px ${C.border2}`:"none"}} onClick={()=>onClick(car)}>
    <div style={{aspectRatio:"16/9",overflow:"hidden",background:"#0c0c0c",position:"relative"}}>
      {fotos[imgIdx]?<img src={fotos[imgIdx]} alt={`${car.marca} ${car.modelo}`} style={{width:"100%",height:"100%",objectFit:"cover",transition:"transform .5s",transform:hov?"scale(1.06)":"scale(1)"}}/>
        :<div style={{width:"100%",height:"100%",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",background:"#111",gap:8}}><span style={{fontSize:36,opacity:.18}}>🚗</span><span style={{fontSize:9,color:C.muted2,letterSpacing:2,textTransform:"uppercase",fontFamily:"sans-serif"}}>Foto próximamente</span></div>}
      <div style={{position:"absolute",top:10,left:10,display:"flex",gap:5}}>
        <span style={{background:car.tipo==="0km"?C.red:"rgba(0,0,0,.8)",border:`1px solid ${car.tipo==="0km"?C.red:C.border2}`,color:"#fff",fontSize:7,padding:"3px 8px",letterSpacing:2,textTransform:"uppercase",fontFamily:"sans-serif",fontWeight:700}}>{car.tipo}</span>
        {car.destacado&&<span style={{background:C.accent,color:"#fff",fontSize:7,padding:"3px 8px",letterSpacing:2,textTransform:"uppercase",fontFamily:"sans-serif",fontWeight:700}}>★ Dest.</span>}
      </div>
      {fotos.length>1&&<div style={{position:"absolute",bottom:8,left:0,right:0,display:"flex",justifyContent:"center",gap:4}}>{fotos.map((_,i)=><button key={i} onClick={e=>{e.stopPropagation();setImgIdx(i);}} style={{width:i===imgIdx?16:6,height:4,background:i===imgIdx?"#fff":"rgba(255,255,255,.38)",border:"none",cursor:"pointer",padding:0,transition:"all .3s"}}/>)}</div>}
    </div>
    <div style={{padding:"18px 18px 20px"}}>
      <div style={{fontSize:8,letterSpacing:3,textTransform:"uppercase",color:C.red,marginBottom:4,fontFamily:"sans-serif",fontWeight:700}}>{car.marca}</div>
      <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:22,fontWeight:800,textTransform:"uppercase",color:C.white,lineHeight:1,marginBottom:5}}>{car.modelo}</div>
      {car.version&&<div style={{fontSize:10,color:C.muted,fontFamily:"sans-serif",marginBottom:8}}>{car.version}</div>}
      <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:12}}>
        {car.anio&&<span style={{fontSize:9,color:C.muted2,fontFamily:"sans-serif"}}>{car.anio}</span>}
        {km&&<span style={{fontSize:9,color:C.muted2,fontFamily:"sans-serif"}}>· {km} km</span>}
        {car.color&&<span style={{fontSize:9,color:C.muted2,fontFamily:"sans-serif"}}>· {car.color}</span>}
      </div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        {price&&<div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:22,fontWeight:700,color:C.white}}>{price}</div>}
        <div style={{fontSize:9,color:C.red,fontFamily:"sans-serif",letterSpacing:1,textTransform:"uppercase",fontWeight:600,marginLeft:"auto"}}>Ver más →</div>
      </div>
    </div>
  </div>;
}

function CarModal({car,onClose,waAle="5493814773142",waGonchi="5493815184961"}){
  const[imgIdx,setImgIdx]=useState(0);const fotos=car.fotos&&car.fotos.length>0?car.fotos:[];
  const km=car.kilometraje!=null?Number(car.kilometraje).toLocaleString("es-AR"):null;
  const price=car.precio_usd?`USD ${Number(car.precio_usd).toLocaleString("es-AR")}`:null;
  const msg=encodeURIComponent(`Hola, me interesa el ${car.marca} ${car.modelo} ${car.anio||""} que vi en la web de NordenCars`);
  useEffect(()=>{document.body.style.overflow="hidden";return()=>{document.body.style.overflow="";};},[]);
  return <div style={{position:"fixed",inset:0,zIndex:900,display:"flex",alignItems:"center",justifyContent:"center",padding:"20px",background:"rgba(0,0,0,.88)"}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{background:C.zinc,maxWidth:860,width:"100%",maxHeight:"90vh",overflowY:"auto",position:"relative"}}>
      <button onClick={onClose} style={{position:"absolute",top:14,right:14,zIndex:10,background:"rgba(0,0,0,.5)",border:"none",color:"#fff",width:36,height:36,cursor:"pointer",fontSize:18,display:"flex",alignItems:"center",justifyContent:"center"}}>×</button>
      <div style={{aspectRatio:"16/9",background:"#0c0c0c",overflow:"hidden",position:"relative"}}>
        {fotos.length>0?<><img src={fotos[imgIdx]} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
          {fotos.length>1&&<><button onClick={()=>setImgIdx(i=>(i-1+fotos.length)%fotos.length)} style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",background:"rgba(0,0,0,.6)",border:"none",color:"#fff",width:36,height:36,cursor:"pointer",fontSize:18}}>‹</button>
            <button onClick={()=>setImgIdx(i=>(i+1)%fotos.length)} style={{position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",background:"rgba(0,0,0,.6)",border:"none",color:"#fff",width:36,height:36,cursor:"pointer",fontSize:18}}>›</button></>}
        </>:<div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center",background:"#0d0d0d"}}><span style={{fontSize:56,opacity:.12}}>🚗</span></div>}
      </div>
      <div style={{padding:"28px 32px"}}>
        <div style={{fontSize:9,letterSpacing:3,color:C.red,fontFamily:"sans-serif",fontWeight:700,marginBottom:4,textTransform:"uppercase"}}>{car.marca}</div>
        <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:36,fontWeight:900,textTransform:"uppercase",color:C.white,lineHeight:1,marginBottom:6}}>{car.modelo}</div>
        {car.version&&<div style={{fontSize:12,color:C.muted,fontFamily:"sans-serif",marginBottom:16}}>{car.version}</div>}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:1,background:C.border,marginBottom:22}}>
          {[["Año",car.anio],["Kilómetros",km?`${km} km`:"—"],["Color",car.color||"—"],["Tipo",car.tipo],["Carrocería",car.carroceria||"—"],["Precio",price||"Consultar"]].map(([k,v])=>(
            <div key={k} style={{background:C.zinc2,padding:"14px 16px"}}><div style={{fontSize:8,letterSpacing:2,textTransform:"uppercase",color:C.muted,fontFamily:"sans-serif",marginBottom:4}}>{k}</div><div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:18,fontWeight:700,color:C.white}}>{v}</div></div>
          ))}
        </div>
        {car.descripcion&&<p style={{fontSize:13,color:"rgba(245,245,245,.48)",lineHeight:1.7,fontFamily:"sans-serif",marginBottom:22}}>{car.descripcion}</p>}
        <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
          <a href={`https://wa.me/${waAle}?text=${msg}`} target="_blank" rel="noreferrer" style={{display:"flex",alignItems:"center",gap:8,background:"#25D366",color:"#fff",padding:"12px 22px",fontSize:10,letterSpacing:2,textTransform:"uppercase",fontFamily:"sans-serif",fontWeight:700,textDecoration:"none",flex:1,justifyContent:"center"}}><WaSvg size={16}/> Consultar a Ale</a>
          <a href={`https://wa.me/${waGonchi}?text=${msg}`} target="_blank" rel="noreferrer" style={{display:"flex",alignItems:"center",gap:8,background:"#25D366",color:"#fff",padding:"12px 22px",fontSize:10,letterSpacing:2,textTransform:"uppercase",fontFamily:"sans-serif",fontWeight:700,textDecoration:"none",flex:1,justifyContent:"center"}}><WaSvg size={16}/> Consultar a Gonchi</a>
        </div>
      </div>
    </div>
  </div>;
}

